={
  "query": "SELECT campaign.name, campaign.status, campaign.id, metrics.cost_micros, metrics.clicks, metrics.impressions, metrics.conversions, metrics.cost_per_conversion FROM campaign WHERE segments.date = '{{ $now.minus({days:1}).toFormat('yyyy-MM-dd') }}' AND campaign.status = 'ENABLED'"
}

parameters.jsCode:
const gadsRaw = $('GET Google Ads Campaigns').all();
const funnel = $('GET Supabase Funnel').first().json;

const rows = [];
for (const item of gadsRaw) {
  const batches = Array.isArray(item.json) ? item.json : [item.json];
  for (const batch of batches) {
    if (batch.results) rows.push(...batch.results);
  }
}

const totals = rows.reduce((acc, row) => {
  const m = row.metrics || {};
  acc.costMicros += parseInt(m.costMicros || 0);
  acc.clicks += parseInt(m.clicks || 0);
  acc.impressions += parseInt(m.impressions || 0);
  acc.conversions += parseFloat(m.conversions || 0);
  return acc;
}, { costMicros: 0, clicks: 0, impressions: 0, conversions: 0 });

totals.spend = (totals.costMicros / 1000000).toFixed(2);
totals.cpc = totals.clicks > 0 ? (totals.costMicros / 1000000 / totals.clicks).toFixed(2) : 'N/A';
totals.cpl = totals.conversions > 0 ? (totals.costMicros / 1000000 / totals.conversions).toFixed(2) : 'N/A';

const sorted = [...rows].sort((a, b) => parseFloat(b.metrics?.conversions || 0) - parseFloat(a.metrics?.conversions || 0));
const topCampaign = sorted[0];

const alertCampaigns = rows.filter(row => {
  const spend = parseInt(row.metrics?.costMicros || 0) / 1000000;
  return spend > 20 && parseFloat(row.metrics?.conversions || 0) === 0;
}).map(row => ({ name: row.campaign?.name, spend: (parseInt(row.metrics?.costMicros || 0) / 1000000).toFixed(2) }));

const campaigns = rows.map(row => ({
  name: row.campaign?.name || 'Unknown',
  spend: (parseInt(row.metrics?.costMicros || 0) / 1000000).toFixed(2),
  clicks: parseInt(row.metrics?.clicks || 0),
  conversions: parseFloat(row.metrics?.conversions || 0)
}));

return [{ json: {
  date: $now.minus({ days: 1 }).toFormat('dd/MM/yyyy'),
  totals, campaigns, alertCampaigns,
  topCampaign: topCampaign ? { name: topCampaign.campaign?.name, conversions: parseFloat(topCampaign.metrics?.conversions || 0), spend: (parseInt(topCampaign.metrics?.costMicros || 0) / 1000000).toFixed(2) } : null,
  funnel: funnel || {}
}}];

